RetornaConfiguracoesPastas.Call(&EmpCod, &FilCod, &SdtConfiguracoespasta)
prcAtualizaCategoriaImposto.Call(&EmpCod, 0) //Atualiza Categorias
&DataHora = ServerNow() //Arquivo onde Salvar &Varchar = trim(toformattedString(&DataHora)) &Varchar = &ImpUfeCod.Trim() + '_TABIMPOSTO_'
Do CAse CAse not &parmPedCod.IsEmpty() &Varchar += 'PEDIDO' + trim(str(&parmPedCod))+ '_' CAse not &parmImpCatCod.IsEmpty() &Varchar += 'CATEGORIA' + trim(str(&parmImpCatCod))+ '_' EndCAse &Varchar += RetornaSoNumeros.Udp(&Varchar)+'.xlsx'
&CaminhoFisico = &SdtConfiguracoespasta.PastaDiretorioTempFis + &Varchar.Trim() &CaminhoVirtual = &SdtConfiguracoespasta.PastaDiretorioTempVir + &Varchar.Trim()
&QtdColunasDiferente = 33
&File.Source = &CaminhoFisico //apaga arquivo gerado com mesmo nome. if &File.Exists() &File.Delete() Endif &File.Close()
//CategoriasPedido if not &parmPedCod.IsEmpty() For Each Order EmpCod, PedCod, ProCatCod Where EmpCod = &EmpCod Where PedCod = &parmPedCod
if ProCatCod <> &oldProCatCod //ADICIONAR OS DIFERENTES. &oldProCatCod = ProCatCod &collProCatCod.Add(ProCatCod) Endif Endfor Endif
//Capta onde o template esta &File.Source = 'Template_TabelaImposto_xltx' &CaminhoTemplate = &File.GetPath() + '\bin\app\Template_TabelaImposto.xltx' &File.Close()
&File.Source = &CaminhoTemplate //Verifica template existe if &File.Exists() &ExcelDocument.Template = &CaminhoTemplate Endif &File.Close()
&ExcelDocument.Open(&CaminhoFisico)
//GravaCampos superiores //FILIAL For each Order EmpCod, TbImpFilCod Where EmpCod = &EmpCod Where TbImpFilCod = &ImpFilCod &ExcelDocument.Cells(1, 3).Text = 'FILIAL: ' + trim(TbImpFilCodNom) &CImpOriUfeCod = TbImpUfeCod Exit EndFor
//LANCAMENTO For Each Order EmpCod, LctCod Where EmpCod = &EmpCod Where LctCod = &ImpLctCod &ExcelDocument.Cells(1, 9).Text = 'LCTO: ' + trim(LctCodNom) Exit EndFor
//UF &ExcelDocument.Cells(1, 20).Text = 'UF: ' + trim(&ImpUfeCod)
//PESSOA For Each Order EmpCod, GruImpCod Where EmpCod = &EmpCod Where GruImpCod = &ImpGruImpCod &ExcelDocument.Cells(1, 26).Text = 'PESSOA: ' + trim(GruImpCodNom) Exit EndFor
//Navega entre as Categorias dos Produtos &linha = 6 For Each order EmpCod, CatCodImp Where EmpCod = &EmpCod Where CatCod = &parmImpCatCod when not &parmImpCatCod.IsEmpty() Where CatCod in &collProCatCod when &parmImpCatCod.IsEmpty() and not &parmPedCod.IsEmpty() Where CatSts = Status_AtivoInativo.ATIVO or CatSts.IsNull() or CatSts.IsEmpty()
if CatSts.IsNull() or CatSts.IsEmpty() or CatCodImp.IsEmpty() or CatCodImp.IsNull() prcAtualizaCategoriaImposto.Call(EmpCod, CatCod) Endif
&ImpCatCod = CatCod &ImpCatCodNom = CatCodImp //CatCodNom Do 'TabelaImposto' EndFor
&linha = 46 For Each order EmpCod, CatCodImp Where EmpCod = &EmpCod where CatCod = &parmImpCatCod when not &parmImpCatCod.IsEmpty() Where CatCod in &collProCatCod when &parmImpCatCod.IsEmpty() and not &parmPedCod.IsEmpty() Where CatSts = Status_AtivoInativo.ATIVO &ImpCatCod = CatCod &ImpCatCodNom = CatCodImp Do 'TabelaImpostoObservacao'
&linha += 1 EndFor
&ExcelDocument.Save() //Salva e fecha &ExcelDocument.Close()
sub 'TabelaImpostoObservacao'
&Count = 0 For Each Order EmpCod, CImpLctCod, CImpTbFilCod, CImpOriUfeCod, CImpDstUfeCod, CImpGruImpCod, CImpCatCod, ObsCod Where EmpCod = &EmpCod Where CImpLctCod = &ImpLctCod Where CImpTbFilCod = &ImpFilCod Where CImpOriUfeCod = &CImpOriUfeCod Where CImpDstUfeCod = &ImpUfeCod Where CImpGruImpCod = &ImpGruImpCod Where CImpCatCod = &ImpCatCod
&Coluna = 1 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom)
&Coluna = 3 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(ObsNom) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(ObsNom) &Count += 1 &linha += 1 When none
&Coluna = 1 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom)
&Coluna = 3 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Count += 1 &linha += 1 EndFor
if &Count < 4 fOR &Aux = &Count to 4 &Coluna = 1 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom) &Coluna = 3 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' &linha += 1 Endfor Endif EndSub
sub 'TabelaImposto' For Each Order EmpCod, CImpLctCod, CImpTbFilCod, CImpOriUfeCod, CImpDstUfeCod, CImpGruImpCod, CImpCatCod Where EmpCod = &EmpCod Where CImpLctCod = &ImpLctCod Where CImpTbFilCod = &ImpFilCod Where CImpOriUfeCod = &CImpOriUfeCod Where CImpDstUfeCod = &ImpUfeCod Where CImpGruImpCod = &ImpGruImpCod Where CImpCatCod = &ImpCatCod
//Preenche campos do xlsx //Produto &Coluna = 1 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom)
//Cfop &Coluna = 3 &ExcelDocument.Cells(&linha, &Coluna).Number = val(trim(RetornaSoNumeros.Udp(CImpCfoCod))) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = val(trim(RetornaSoNumeros.Udp(CImpCfoCod)))
//CSOSN / CST &Coluna = 4 &ExcelDocument.Cells(&linha, &Coluna).Text = CImpCstCod.ToString() &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = CImpCstCod.ToString()
//ALIQ. ICMS &Coluna = 6 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmInt &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmInt
//REDUCAO ICMS &Coluna = 7 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpRedAlqIcmInt &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpRedAlqIcmInt
//DIFERIMENTO ICMS &Coluna = 8 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpDif &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpDif
//DIFAL ICMS &Coluna = 9 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmUFDest &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmUFDest
//COD. CBENEF &Coluna = 10 &ExcelDocument.Cells(&linha, &Coluna).Text = CImpCBenef &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = CImpCBenef
//COD DESONERACAO &Coluna = 11 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(CImpIcmsMotDes) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(CImpIcmsMotDes)
//DESTACAR ICMS RETIDO &Coluna = 12 Do Case case CImpIcmsRet = 'S' &ExcelDocument.Cells(&linha, &Coluna).Text = 'SIM' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = 'SIM' case CImpIcmsRet = 'N' &ExcelDocument.Cells(&linha, &Coluna).Text = 'NAO' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = 'NAO' otherwise &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' EndCAse
//EXCLUIR DA BASE &Coluna = 13 If CImpExcPisCofins = 'S' // 'SIM' &ExcelDocument.Cells(&linha, &Coluna).Text = 'SIM' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text ='SIM' Else &ExcelDocument.Cells(&linha, &Coluna).Text = 'NAO' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text ='NAO' Endif
//ALIQ ICMS ST &Coluna = 15 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmExt &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmExt
//MVA ICMS ST &Coluna = 16 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqMVA &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqMVA
//REDUCAO ICMS ST &Coluna = 17 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpRedAlqIcmExt &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpRedAlqIcmExt
//FECOP ICMS ST &Coluna = 18 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpTaxFecop &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpTaxFecop
//DIFAL S.T &Coluna = 19 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmStUF &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpAlqIcmStUF
//ALIQ IPI &Coluna = 21 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpIpi &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpIpi
//CST IPI &Coluna = 22 if not CImpCstIpi.IsNull() and not CImpCstIpi.IsEmpty() &ExcelDocument.Cells(&linha, &Coluna).Text = trim(CImpCstIpi.ToString()) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(CImpCstIpi.ToString()) Else &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' Endif
//INCLUIR NA BASE &Coluna = 23 Do Case case CImpIncIPI = 'S' &ExcelDocument.Cells(&linha, &Coluna).Text = 'ICMS ST' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = 'ICMS ST' case CImpIncIPI = 'I' &ExcelDocument.Cells(&linha, &Coluna).Text = 'ICMS' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = 'ICMS' Otherwise &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' EndCAse
//COD ENQUADR &Coluna = 24 if not CImpIpiEnq.IsEmpty() and not CImpIpiEnq.IsNull() &ExcelDocument.Cells(&linha, &Coluna).Number = CImpIpiEnq &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpIpiEnq Else &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' Endif
//ALIQ PIS &Coluna = 26 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpPis &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpPis
//REDUCAO PIS &Coluna = 27 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpPisRed &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpPisRed
//CST PIS &Coluna = 28 if not CImpCstPisCofins.IsEmpty() and not CImpCstPisCofins.IsNull() &ExcelDocument.Cells(&linha, &Coluna).Text = trim(CImpCstPisCofins.ToString()) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(CImpCstPisCofins.ToString()) Else &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' Endif
//ALIQ COFINS &Coluna = 30 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpCofins &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpCofins
//REDUCAO COFINS &Coluna = 31 &ExcelDocument.Cells(&linha, &Coluna).Number = CImpCofinsRed &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Number = CImpCofinsRed
//CST COFINS &Coluna = 32 &Varchar = CImpCstPisCofins.ToString() if not &Varchar.IsEmpty() &ExcelDocument.Cells(&linha, &Coluna).Text = &Varchar &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = &Varchar Else &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = '' Endif
Exit When none
//Preenche campos do xlsx //Produto &Coluna = 1 &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom) &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = trim(&ImpCatCodNom)
//Cfop &Coluna = 3 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//CSOSN / CST &Coluna = 4 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//ALIQ. ICMS &Coluna = 6 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//REDUCAO ICMS &Coluna = 7 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//DIFERIMENTO ICMS &Coluna = 8 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//DIFAL ICMS &Coluna = 9 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//COD. CBENEF &Coluna = 10 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//COD DESEONERACAO &Coluna = 11 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//DESTACAR ICMS RETIDO &Coluna = 12 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//EXCLUIR DA BASE &Coluna = 13 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//ALIQ ICMS ST &Coluna = 15 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//MVA ICMS ST &Coluna = 16 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//REDUCAO ICMS ST &Coluna = 17 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//FECOP ICMS ST &Coluna = 18 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//DIFAL S.T &Coluna = 19 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//ALIQ IPI &Coluna = 21 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//CST IPI &Coluna = 22 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//INCLUIR NA BASE &Coluna = 23 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//COD ENQUADR &Coluna = 24 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//ALIQ PIS &Coluna = 26 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//REDUCAO PIS &Coluna = 27 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//CST PIS &Coluna = 28 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//ALIQ COFINS &Coluna = 30 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//REDUCAO COFINS &Coluna = 31 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
//CST COFINS &Coluna = 32 &ExcelDocument.Cells(&linha, &Coluna).Text = '' &Coluna += &QtdColunasDiferente &ExcelDocument.Cells(&linha, &Coluna).Text = ''
EndFor
&linha += 1 EndSub
